using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Text.RegularExpressions;
using System.Web.Mvc;
using System.Data.Entity;

namespace MyStore.Web.Controllers
{
    public class ProductReviewsController : Controller
    {
        private readonly ApplicationDbContext _db;

        public ProductReviewsController() : this(new ApplicationDbContext())
        {
        }

        public ProductReviewsController(ApplicationDbContext db)
        {
            _db = db;
        }

        [HttpGet]
        public ActionResult Product(int id)
        {
            var product = _db.Products
                .AsNoTracking()
                .FirstOrDefault(p => p.Id == id);

            if (product == null)
                return HttpNotFound();

            var reviews = _db.Reviews
                .AsNoTracking()
                .Where(r => r.ProductId == id && r.IsApproved)
                .OrderByDescending(r => r.CreatedAt)
                .Select(r => new ReviewViewModel
                {
                    Id = r.Id,
                    AuthorName = r.AuthorName,
                    Rating = r.Rating,
                    CreatedAt = r.CreatedAt,
                    ContentHtml = ReviewFormatting.SanitizeAndFormat(r.Content)
                })
                .ToList();

            var model = new ProductReviewsPageViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews
            };

            return View("Product", model);
        }
    }

    public static class ReviewFormatting
    {
        public static string SanitizeAndFormat(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
                return string.Empty;

            string encoded = WebUtility.HtmlEncode(input);

            encoded = Regex.Replace(encoded, @"\*\*(.+?)\*\*", "<strong>$1</strong>", RegexOptions.Singleline);
            encoded = Regex.Replace(encoded, @"__(.+?)__", "<strong>$1</strong>", RegexOptions.Singleline);
            encoded = Regex.Replace(encoded, @"\*(.+?)\*", "<em>$1</em>", RegexOptions.Singleline);
            encoded = Regex.Replace(encoded, @"_(.+?)_", "<em>$1</em>", RegexOptions.Singleline);

            return encoded;
        }
    }

    public class ProductReviewsPageViewModel
    {
        public int ProductId { get; set; }
        public string ProductName { get; set; }
        public IList<ReviewViewModel> Reviews { get; set; } = new List<ReviewViewModel>();
    }

    public class ReviewViewModel
    {
        public int Id { get; set; }
        public string AuthorName { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedAt { get; set; }
        public string ContentHtml { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string AuthorName { get; set; }
        public int Rating { get; set; }
        public string Content { get; set; }
        public bool IsApproved { get; set; }
        public DateTime CreatedAt { get; set; }
    }

    public class ApplicationDbContext : DbContext
    {
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

@model MyStore.Web.Controllers.ProductReviewsPageViewModel

@{
    ViewBag.Title = Model.ProductName;
}

<h1>@Model.ProductName</h1>

<div class="product-reviews">
    <h2>Customer Reviews</h2>

    @if (Model.Reviews == null || !Model.Reviews.Any())
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var review in Model.Reviews)
        {
            <div class="review">
                <div class="review-meta">
                    <strong>@review.AuthorName</strong>
                    <span>@review.CreatedAt.ToString("MMMM d, yyyy")</span>
                    <span>Rating: @review.Rating</span>
                </div>
                <div class="review-content">
                    @Html.Raw(review.ContentHtml)
                </div>
            </div>
        }
    }
</div>